#!/usr/bin/env python3\n"""\nEnsure Django logs directory exists before starting server.\n\nUsage: cd fundvision_backend &amp;&amp; python setup_logs.py\n"""\n\nimport os\nfrom pathlib import Path\n\n# Django BASE_DIR style\nBASE_DIR = Path(__file__).resolve().parent\nlogs_dir = BASE_DIR / "logs"\nlog_file = logs_dir / "fundvision.log"\n\nprint(f"Ensuring logs dir: {{logs_dir}}")\nlogs_dir.mkdir(exist_ok=True)\n\nif not log_file.exists():\n    log_file.touch()\n    print(f"Created {{log_file}}")\nelse:\n    print(f"{{log_file}} already exists")\n\nprint("✅ Logs directory ready for Django!")\n
